var wurld = 1;
var flow = false;
var maro = false;
function draw() {
  mario.collide(luck);
  mario.collide(l);
  if (spik.x < 0) {
    spik.x = 200;
    flow = false;
    spik.velocityY = -14;
  }
  if (mario.x > 110 && wurld == 2) {
    maro = true;
  }
  if (mario.isTouching(spik)) {
    gameover = true;
    mariotuch = false;
  }
  if (maro == true) {
    piran.setFrame(2);
    piran.scale = 0.15;
    piran.setCollider("rectangle", 0, 0, 200, 550);
    spik.rotationSpeed = -10;
    spik.velocityX = -1;
    if (spik.velocityY == 0 && flow == false) {
    spik.velocityY = randomNumber(-11, -14);
    }
    spik.velocityY = spik.velocityY + 0.4;
    if (spik.y >= 370) {
    spik.y = 370;
    spik.velocityY = spik.velocityY * -0.6; 
    spik.velocityX = -10;
    }
    if (flow == true) {
      spik.velocityY = 0;
      spik.velocityY = spik.velocityY + 5;
    }
    if (piran.y < 297) {
      piran.velocityY = piran.velocityY + 0.2;
    } else if ((piran.y > 314)) {
      piran.velocityY = piran.velocityY - 0.2;
    }
  } else if ((wurld == 2)) {
    piran.y = 318;
    spik.y = 300;
    piran.velocityY = 0;
  }
  if (mario.isTouching(piran) && wurld == 2) {
    gameover = true;
    mariotuch = false;
    homer.setCollider("rectangle", 0, 0, 0, 0);
  }
  if (flameflower.y <= 229) {
    flameflower.velocityY = 2;
    flameflower.velocityX = 0;
  }
  if (mario.isTouching(luck)) {
    luck.tint = 80;
    flameflower.velocityY = -2;
    flameflower.velocityX = -2;
  }
  if (flameflower.y >= 364) {
    flameflower.velocityY = 0;
  }
  goombahitbox2.x = goomba.x;
  var time = World.seconds;
  if (goomba.x < 5) {
    goomba.velocityX = 3;
  }
  if (goomba.x > 340) {
    goomba.velocityX = -3;
  }
  if ((keyWentDown("up") && jumpsLeft > 0 && cooldownTimer == 0) && mario.isTouching(flameflower)) { 
      jumping = true;
    jumpPower = -7;
    mario.setAnimation("difficulty jumping");
    jumpsLeft = jumpsLeft - 1;  
  } else if ((keyWentDown("up") && jumpsLeft > 0 && cooldownTimer == 0)) {
    jumping = true;
    jumpPower = -7;
    mario.setAnimation("Jump");
    jumpsLeft = jumpsLeft - 1;
  }
  if (jumping) {
    mario.velocityY = jumpPower;
    jumpPower += gravity;
  }
  if (cooldownTimer > 0) {
    cooldownTimer = cooldownTimer - 1;
    if (cooldownTimer == 0) {
        jumpsLeft = 2;
            }
      }

  if (mario.isTouching(block) && mario.velocityY < 0 && mario.y > block.y) {
  mario.velocityY = 0;
  jumpPower = 0;
  } else if (mario.isTouching(block) && mario.y <= block.y) {
  mario.y = block.y - 25;
  mario.velocityY = 0;
  jumping = false;
  jumpPower = 0;
  groundLevel = block.y - 25;
  if (jumpsLeft == 0) {
    cooldownTimer = cooldownTime;
  }
  } else if ((wurld == 4)) {
  groundlevel = 340;
  } else {
    groundLevel = 364.1;
  }
  if (wurld == 2) {
    flameflower.y = mario.y;
    spik.scale = 0.07;
  }

if (mario.y >= groundLevel && (!gameover || mariotuch)) {
  mario.y = groundLevel - 1;
  mario.velocityY = 0;
  jumping = false;
  jumpPower = 0;
  if (jumpsLeft == 0) {
    cooldownTimer = cooldownTime;
  }
}
  if (wurld == 4) {
    flameflower.x = mario.x;
    groundLevel = 340;
    flame.bounceOff(florr);
  }
  if (mario.isTouching(lucky) && blockhit == false) {
    lucky.tint = 80;
    blockhit = true;
    ifcoinorshroom = randomNumber(1, 10);
  }
  if (5 >= ifcoinorshroom) {
    Cooin1.velocityY = 0;
    if (shroom.y == block.y - 20) {
      shroom.velocityY = 0;
    } else if ((mario.collide(lucky))) {
      shroom.y = shroom.y - 4;
    }
  }
  if (ifcoinorshroom > 5 && ifcoinorshroom > 0) {
        shroom.velocityY = 0;
        if (Cooin1.y == block.y - 20) {
        Cooin1.velocityY = 0;
    } else {
        Cooin1.y = Cooin1.y - 4;
    }
  }
  // shroom alter
  //shroom alter
  if (mario.isTouching(shroom)) {
    shroom.visible = 0;
    mario.scale = 0.08;
  }
  if (mario.scale == 0.08) {
    groundLevel = 350;
    gravity = 0.3;
  }
  if (mario.collide(Cooin1)) {
    Cooin1.visible = 0;
    Cooin1.x = 0;
    Cooin1.y = 0;
    coins = coins + 1;
  }
  if (mario.isTouching(goombahitbox2) || fire.isTouching(goomba)) {
    goomba.setCollider("rectangle", 0, 0, 0, 0);
    goomba.pause();
    goomba.velocityX = 0;
    goomba.rotateToDirection = 320;
    mariotuch = true;
    goomba.height = goomba.height - 4;
    goomba.velocityY = 2;
    piran.y = 315;
    if (goombahit == false) {
      score = score + 1;
      goombahit = true;
    }
  }
  if (mario.x < 3) {
    mario.x = 3;
  }
  mario.collide(pipe);
  mario.collide(homer);
  drawSprites();
  fire.velocityY = fire.velocityY + 0.3;
  if (gameover && mariotuch == false) {
    textFont("Pixel");
    fill("white");
    textSize(50);
    text("GAME OVER", 65, 230);
    // ConsleCC
    goomba.velocityX = 0;
    piran.velocityY = 0;
    mario.scale = 0.1;
    goomba.pause();
    mario.setAnimation("Itsameadeadmario");
    mario.velocityX = 0;
    mario.velocityY = mario.velocityY + 0.4;
    flame.velocityY = 0;
    bowser.destroy();
    shoot.velocityX = 0;
    groundLevel = 700;
    jumping = true;
    flame.rotationSpeed = 0;
  } else if ((mario.isTouching(flameflower))) {
    flameflower.visible = 0;
    flameflower.x = mario.x;
    flameflower.y = mario.y;
    if (keyWentDown("down")) {
      fire.x = mario.x;
      fire.y = mario.y;
      fire.rotationSpeed = 9;
      fire.velocityX = 5;
      fire.velocityY = 1;
    }
    if (fire.y >= 370 && fire.velocityY > 0) {
        fire.velocityY = fire.velocityY * -0.9;
        fire.y = 370;
    }
    if (keyDown("left") || keyDown("right")) {
      if (keyDown("right")) {
       mario.x = mario.x + 4;
       mario.setAnimation("Flame Mario walk");
      }
      if (keyDown("left")) {
        mario.x = mario.x - 4;
        mario.setAnimation("Flame Mario walk_copy_1");
      }
    } else {
      mario.velocityX = 0;
      mario.setAnimation("Flamemario");
    }
  } else if ((keyDown("left"))) {
    mario.velocityX = -4;
    mario.setAnimation("Mario walk backward");
  } else if ((keyDown("right"))) {
    mario.velocityX = 4;
    mario.setAnimation("Mario walk");
  } else {
    mario.velocityX = 0;
    mario.setAnimation("Mario");
  }
  if (mario.isTouching(goomba)) {
    gameover = true;
    goombahitbox2.destroy();
  }
  if (mario.scale == 0.4) {
    l.y = -160;
  }
  if (wurld == 3) {
    spik.destroy();
  }
  fill("white");
  textFont("Super Legend Boy");
  textSize(20);
  text("WORLD", 215, 40);
  text("MARIO", 30, 40);
  text("000000", 30, 60);
  text(score, 90, 60);
  text("-4", 245, 60);
  text(wurld, 235, 60);
  text("x", 167, 60);
  text(coins, 180, 61);
  text("TIME", 320, 40);
  text(time, 340, 60);
  textSize(12);
  if (wurld == 4 && mario.x >= 400) {

  }
  if (wurld == 1) {
    text("DOWN TO FIRE", 18, 310);
    text("ARROWKEYS AND", 10, 295);
  }
  if ((mario.x > 345 && mario.y > 350) && wurld == 1) {
    pipe2.y = 10;
    if (mario.isTouching(flameflower)) {
      flameflower.x = mario.x;
      flameflower.y = mario.y;
    } else {
      flameflower.destroy();
    }
    mario.velocityY = mario.velocityY + 10;
    homer.y = 355;
    shroom.destroy();
    goomba.destroy();
    block.destroy();
    lucky.destroy();
    luck.destroy();
    Cooin1.destroy();
    goombahitbox2.destroy();
    l.destroy();
    pipe.destroy();
    piran.visible = 1;
    homer.visible = 1;
    wurld = wurld + 1;
    mario.x = 26;
    mario.y = 19;
    flameflower.x = 23;
    pipe2.scale = 0.115;
    pipe2.visible = 1;
    pipe2.setCollider("rectangle", 0, 0, 0, 0);
  }
  fire.bounceOff(luck);
  fire.bounceOff(lucky);
  fire.bounceOff(block);
  fire.bounceOff(pipe);
  fire.bounceOff(pipe2);
  fire.bounceOff(homer);
  if (wurld == 2) {
    fire.bounceOff(homer);
    textSize(27);
    fill("Red");
    text(bosshealth, 130, 127);
    text("Piranha:", 40, 127);
    if (fire.bounceOff(piran)) {
      bosshealth = bosshealth - 10;
    }
    if (bosshealth == 0) {
      piran.alpha = piran.alpha - 0.2;
      score = 20;
      piran.destroy();
      spik.destroy();
    }
  }
  if (wurld == 2 && mario.x >= 400) {
    pipe2.destroy();
    piran.destroy();
    homer.destroy();
    wurld = 3;
    flameflower.x = 0;
    mario.x = 0;
    floor2.visible = 1;
    floor2.y = 400;
    floor2.x = 300;
  }
  if (wurld == 3 && mario.x >= 400) {
   groundLevel = 340;
   florr.scale = 0.81;
   florr.visible = 1;
   florr.x = 300;
   florr.y = 369.8;
   floor2.x = 90;
   floor2.y = 380;
   final.visible = 1;
   back.visible = 1;
   floor.destroy;

   wurld = 4;
   mario.x = 0;
   fire.x = 0;
   flameflower.x = 0;
   flame.y = 400;
   flame.velocityY = flame.velocityY - 12;
   bowser.y = 330;
   hammer.y = 330;
   shoot.y = 330;
   shoot.scale = 0.5;
   shoot.velocityX = shoot.velocityX - 2;
  }
  if (mario.isTouching(flame)) {
    gameover = true;
    mariotuch = false;
  }
  if (wurld == 4) {
    flame.rotationSpeed = 5;
    flameflower.y = mario.y;
    if ((flame.y) <= 205) {
      flame.velocityY = flame.velocityY + 0.5;
    }
    flame.velocityX = 0;
    flame.visible = 1;
    if (flame.y >= 600) {
    flame.x = randomNumber(50, 350);
    flame.velocityY = flame.velocityY - 12;
  }
  bowsercooldown = bowsercooldown + 1;
  if (bowsercooldown >= 90) {
    bowserjumping = true;
    bowserjumppower = -10;
    bowsercooldown = 0;
  }

  if (bowserjumping) {
    bowser.velocityY = bowserjumppower;
    bowserjumppower = bowserjumppower + 1.5;
  }

  if (bowser.y > 330) {
    bowser.y = 330;
    bowser.velocityY = 0;
    bowserjumping = false;
    bowserjumppower = 0;
  }

  if (fire.isTouching(bowser)) {
    bowserhealth = bowserhealth - 10;
    fire.x = -100;  
    fire.velocityX = 0;
    fire.velocityY = 0;
  }

  if (bowserhealth <= 0) {
    bowser.alpha = bowser.alpha - 0.05;
    bowser.mirrorY(-1);
    bowser.y = bowser.y + 5;
    if ((bowser.alpha) <= 0) {
      bowser.destroy();
      flame.destroy();
      score = 120;
    }
  }
    if (shoot.x < 0) {
      shot();
    }

  if (mario.isTouching(bowser)) {
    gameover = true;
    mariotuch = false;
  }
    if (shoot.isTouching(mario)) {
      gameover = true;
      mariotuch = false;
    }

  fill("red");
  textFont("Super Legend Boy");
  textSize(27);
  text("Bowser:", 40, 127);
  text(bowserhealth, 145, 127);




if (bowserjumping == true) {
      hammerbb();
    }

if (hammerthrown) {
    hammerthrowns();
}

if (hammer3.y >= 400) {
    hammerback();
  hammerthrown = false;
}

if ((mario.isTouching(hammer) || mario.isTouching(hammer1)) || (mario.isTouching(hammer2) || mario.isTouching(hammer3))) {
      gameover = true;
      mariotuch = false;
      hammer.visible = 0;
    }
  }
}
function shot() {
  shoot.x = bowser.x - 10;
}
function hammerbb() {
  hammer.x = bowser.x;
  hammer.y = bowser.y;
  hammer1.x = bowser.x;
  hammer1.y = bowser.y;
  hammer2.x = bowser.x;
  hammer2.y = bowser.y;
  hammer3.x = bowser.x;
  hammer3.y = bowser.y;
  hammer.velocityX = -2;
  hammer.velocityY = -8;
  hammer.visible = 1;
  hammer1.velocityX = -3;
  hammer1.velocityY = -7.5;
  hammer1.visible = 1;
  hammer2.velocityX = -3.5;
  hammer2.velocityY = -7;
  hammer2.visible = 1;
  hammer3.velocityX = -4;
  hammer3.velocityY = -7;
  hammer3.visible = 1;
  hammerthrown = true;
}
function hammerthrowns() {
  hammer.velocityY = hammer.velocityY + 0.3;
  hammer1.velocityY = hammer1.velocityY + 0.3;
  hammer2.velocityY = hammer2.velocityY + 0.3;
  hammer3.velocityY = hammer3.velocityY + 0.3;
}
function hammerback() {
  hammer.visible = 0;
  hammer.x = 800;
  hammer.y = 800;
  hammer.velocityX = 0;
  hammer.velocityY = 0;
  hammer1.visible = 0;
  hammer1.x = 800;
  hammer1.y = 800;
  hammer1.velocityX = 0;
  hammer1.velocityY = 0;
  hammer2.visible = 0;
  hammer2.x = 800;
  hammer2.y = 800;
  hammer2.velocityX = 0;
  hammer2.velocityY = 0;
  hammer3.visible = 0;
  hammer3.x = 800;
  hammer3.y = 800;
  hammer3.velocityX = 0;
  hammer3.velocityY = 0;

}
